// WeaponString retrieves an enum value from the enum constants string name.
// Throws an error if the param is not part of the enum.
func WeaponString(s string) (Weapon, error) {
	if val, ok := _WeaponNameToValueMap[s]; ok {
		return val, nil
	}

	if val, ok := _WeaponNameToValueMap[strings.ToLower(s)]; ok {
		return val, nil
	}
	return 0, fmt.Errorf("%s does not belong to Weapon values", s)
}

// WeaponValues returns all values of the enum
func WeaponValues() []Weapon {
	return _WeaponValues
}

// WeaponStrings returns a slice of all String values of the enum
func WeaponStrings() []string {
	strs := make([]string, len(_WeaponNames))
	copy(strs, _WeaponNames)
	return strs
}

// IsAWeapon returns "true" if the value is listed in the enum definition. "false" otherwise
func (i Weapon) IsAWeapon() bool {
	for _, v := range _WeaponValues {
		if i == v {
			return true
		}
	}
	return false
}

// MarshalJSON implements the json.Marshaler interface for Weapon
func (i Weapon) MarshalJSON() ([]byte, error) {
	return json.Marshal(i.String())
}

// UnmarshalJSON implements the json.Unmarshaler interface for Weapon
func (i *Weapon) UnmarshalJSON(data []byte) error {
	var s string
	if err := json.Unmarshal(data, &s); err != nil {
		return fmt.Errorf("Weapon should be a string, got %s", data)
	}

	var err error
	*i, err = WeaponString(s)
	return err
}

// MarshalText implements the encoding.TextMarshaler interface for Weapon
func (i Weapon) MarshalText() ([]byte, error) {
	return []byte(i.String()), nil
}

// UnmarshalText implements the encoding.TextUnmarshaler interface for Weapon
func (i *Weapon) UnmarshalText(text []byte) error {
	var err error
	*i, err = WeaponString(string(text))
	return err
}
